import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import './Auth.css';

const Register = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '', confirmPassword: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData((prev) => ({ ...prev, [e.target.name]: e.target.value }));
    setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const { name, email, password, confirmPassword } = formData;
    if (!name.trim() || !email.trim() || !password || !confirmPassword) {
      setError('All fields are required.'); return;
    }
    if (name.trim().length < 2) { setError('Name must be at least 2 characters.'); return; }
    if (password.length < 6) { setError('Password must be at least 6 characters.'); return; }
    if (password !== confirmPassword) { setError('Passwords do not match.'); return; }

    try {
      setLoading(true);
      const { data } = await axios.post('/api/auth/register', {
        name: name.trim(), email: email.trim(), password
      });
      login(data.user, data.token);
      navigate('/', { replace: true });
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const getStrength = (pass) => {
    if (!pass) return null;
    if (pass.length < 6) return { width: '20%', color: '#dc2626', label: 'Too short' };
    if (pass.length < 8) return { width: '45%', color: '#d97706', label: 'Fair' };
    if (/(?=.*[a-z])(?=.*[A-Z])(?=.*[0-9])/.test(pass)) return { width: '100%', color: '#059669', label: 'Strong 💪' };
    return { width: '72%', color: '#0891b2', label: 'Good' };
  };
  const strength = getStrength(formData.password);

  return (
    <div className="auth-page">
      {/* Left Panel */}
      <div className="auth-left">
        <div className="auth-left-blob auth-left-blob-1" />
        <div className="auth-left-blob auth-left-blob-2" />
        <div className="auth-brand">
          <div className="auth-brand-logo">💙 Fund<span>It</span></div>
          <div className="auth-brand-tagline">Changing lives, one rupee at a time.</div>
        </div>
        <div className="auth-testimonial">
          <p className="auth-testimonial-text">
            "Within 48 hours of starting our campaign, we had 200 donors.
            FundIt is incredibly easy to use and the team is so supportive."
          </p>
          <div className="auth-testimonial-author">
            <div className="auth-testimonial-avatar">A</div>
            <div>
              <div className="auth-testimonial-name">Ankit Mehta</div>
              <div className="auth-testimonial-role">Mumbai — NGO Founder</div>
            </div>
          </div>
        </div>
      </div>

      {/* Right Form Panel */}
      <div className="auth-right">
        <div className="auth-form-wrapper" id="register-form-container">
          <div className="auth-form-header">
            <Link to="/" className="auth-back-link" id="back-to-home">← Back to campaigns</Link>
            <h1 className="auth-form-title">Create your account</h1>
            <p className="auth-form-subtitle">Join FundIt and start making a real difference today.</p>
          </div>

          {error && (
            <div className="alert alert-error" id="register-error-alert" role="alert">
              <span>⚠️</span>
              <p>{error}</p>
            </div>
          )}

          <form onSubmit={handleSubmit} noValidate id="register-form">
            <div className="form-group">
              <label className="form-label" htmlFor="register-name">Full Name</label>
              <input
                id="register-name"
                name="name"
                type="text"
                className="form-input"
                placeholder="e.g., Priya Sharma"
                value={formData.name}
                onChange={handleChange}
                autoComplete="name"
                required
              />
            </div>

            <div className="form-group">
              <label className="form-label" htmlFor="register-email">Email Address</label>
              <input
                id="register-email"
                name="email"
                type="email"
                className="form-input"
                placeholder="you@example.com"
                value={formData.email}
                onChange={handleChange}
                autoComplete="email"
                required
              />
            </div>

            <div className="form-group">
              <label className="form-label" htmlFor="register-password">Password</label>
              <input
                id="register-password"
                name="password"
                type="password"
                className="form-input"
                placeholder="Minimum 6 characters"
                value={formData.password}
                onChange={handleChange}
                autoComplete="new-password"
                required
              />
              {strength && (
                <div className="password-strength" id="password-strength-indicator">
                  <div className="strength-bar">
                    <div className="strength-fill" style={{ width: strength.width, background: strength.color }} />
                  </div>
                  <span className="strength-label" style={{ color: strength.color }}>{strength.label}</span>
                </div>
              )}
            </div>

            <div className="form-group">
              <label className="form-label" htmlFor="register-confirm-password">Confirm Password</label>
              <input
                id="register-confirm-password"
                name="confirmPassword"
                type="password"
                className="form-input"
                placeholder="Re-enter your password"
                value={formData.confirmPassword}
                onChange={handleChange}
                autoComplete="new-password"
                required
              />
              {formData.confirmPassword && (
                <span className={`input-hint ${formData.password === formData.confirmPassword ? 'input-hint-success' : 'input-hint-error'}`}>
                  {formData.password === formData.confirmPassword ? '✓ Passwords match' : '✗ Passwords don\'t match'}
                </span>
              )}
            </div>

            <button
              type="submit"
              className="auth-submit-btn"
              disabled={loading}
              id="btn-register-submit"
            >
              {loading ? <><span className="spinner" />Creating account...</> : 'Create My Account'}
            </button>
          </form>

          <p className="input-hint" style={{ textAlign: 'center', marginTop: '1rem' }}>
            By signing up, you agree to our Terms of Service and Privacy Policy.
          </p>

          <div className="auth-footer">
            <p>Already have an account? <Link to="/login" id="link-to-login">Sign in</Link></p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Register;
